    refreshStartupsWithRetry(retries = 2, delayMs = 1000) {
      this.loadStartups();
      if (retries <= 0) {
        return;
      }
      setTimeout(() => {
        if (!this.startups?.length) {
          this.refreshStartupsWithRetry(retries - 1, delayMs);
        }
      }, delayMs);
    }
    toggleCreateForm() {
